mapper.select:
SELECT pb.id, pb.book_date, pb.book_type, pb.amount, pb.category_id, bc.name AS category_name, pb.description, pb.card_id, c.card_no_last4, c.bank_name, pb.create_time FROM personal_book pb LEFT JOIN book_category bc ON bc.id = pb.category_id AND bc.is_deleted = 0 LEFT JOIN bank_card c ON c.id = pb.card_id AND c.is_deleted = 0 WHERE pb.is_deleted = 0 AND pb.book_type = #{bookType}
AND pb.category_id IN #{id}
AND pb.card_id = #{cardId} AND pb.book_date >= #{bookDateStart} AND pb.book_date <= #{bookDateEnd} ORDER BY pb.book_date DESC, pb.create_time DESC
